        if (currentSaleStatus != SaleStatus.PublicSale) revert SaleNotActive();
        if (amount == 0) revert InvalidAmount();

        _mint(amount);
    }

    function _mint(uint256 amount) private {
        if (supply + amount > maxSupply) revert ExceedsMaxSupply();
        if (msg.value != cost * amount) revert WrongEtherAmount();

        supply += amount;
    }
}
